export function script(input) {
  const matches = Array.isArray(input.matches) ? input.matches : [];
  const analyticsResults = Array.isArray(input.results) ? input.results : [];
  const targetLabel = typeof input.targetLabel === 'string' && input.targetLabel.trim().length > 0 ? input.targetLabel.trim() : 'payload';
  const targetContent = typeof input.targetContent === 'string' ? input.targetContent : '';
  const authorizationNotes = typeof input.authorizationNotes === 'string' && input.authorizationNotes.trim().length > 0 ? input.authorizationNotes.trim() : null;
  const severityRank = { critical: 4, high: 3, medium: 2, low: 1, info: 0, none: 0 };
  const normalizeTag = (value) => String(value || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
  const severityFor = (match) => {
    const tags = Array.isArray(match?.tags) ? match.tags.map(normalizeTag) : [];
    if (tags.some((tag) => /credential|secret|exfiltration|ransomware|trojan|backdoor|exploit|malware/.test(tag))) return 'high';
    if (tags.some((tag) => /ioc|suspicious|shell|encoded|webshell|loader/.test(tag))) return 'medium';
    return 'medium';
  };
  const matchedStringsFor = (match) => Array.isArray(match?.strings) ? match.strings.map(String).filter(Boolean) : [];
  const priorityFindings = matches.map((match) => {
    const tags = Array.isArray(match?.tags) ? match.tags.map(String).filter(Boolean) : [];
    const matchedStrings = matchedStringsFor(match);
    const severity = severityFor(match);
    return {
      rule: String(match?.rule || 'unknown-rule'),
      severity,
      tags,
      matchedStrings: matchedStrings.length,
      evidence: matchedStrings.slice(0, 10).map((item) => item.slice(0, 240)),
      priorityScore: (severityRank[severity] || 0) * 100 + Math.min(matchedStrings.length, 10) * 5 + Math.min(tags.length, 5)
    };
  }).sort((a, b) => b.priorityScore - a.priorityScore || String(a.rule).localeCompare(String(b.rule)));
  const highestSeverity = priorityFindings.reduce((current, finding) => (severityRank[finding.severity] || 0) > (severityRank[current] || 0) ? finding.severity : current, 'none');
  const analyticsByRule = analyticsResults.slice(0, 100).map((result) => ({
    scanner: result?.scanner || 'yara',
    finding_hash: result?.finding_hash || null,
    severity: result?.severity || null,
    asset_key: result?.asset_key || null,
    rule: result?.rule || null,
    matched_strings: result?.matched_strings || 0
  }));
  return {
    report: {
      summary: {
        targetLabel,
        targetBytes: targetContent.length,
        ruleCountEstimate: String(input.rules || '').split(/\brule\s+/).filter((item) => item.trim().length > 0).length,
        matchCount: matches.length,
        reportedFindings: priorityFindings.length,
        highestSeverity
      },
      authorizationNotes,
      priorityFindings,
      analyticsResults: analyticsByRule,
      rawPreview: typeof input.raw === 'string' ? input.raw.slice(0, 2000) : '',
      nextSteps: [
        'Confirm the payload source and authorization before sharing evidence',
        'Treat high-severity credential, exfiltration, exploit, or malware-tagged rules as priority manual review',
        'Replace the fixture rule with engagement-specific YARA rules before real triage',
        'Preserve only minimal matched-string evidence needed for reporting'
      ]
    }
  };
}
